package devportal

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/devportal"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/devportal/appsettings"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type DevPortalAppSettingsProxy struct {
	devportal.UnimplementedDevPortalAppSettingsServer
	client devportal.DevPortalAppSettingsClient
}

func init() {
	proxyutil.Register(&devportal.DevPortalAppSettings_ServiceDesc, NewDevPortalAppSettingsProxy)
}
func NewDevPortalAppSettingsProxy(cc grpc.ClientConnInterface) devportal.DevPortalAppSettingsServer {
	return &DevPortalAppSettingsProxy{client: devportal.NewDevPortalAppSettingsClient(cc)}
}
func (p *DevPortalAppSettingsProxy) GetForm(ctx context.Context, in *appsettings.GetAppSettingsFormRequest) (*appsettings.GetAppSettingsFormResponse, error) {
	return proxyutil.ProxyMethod[appsettings.GetAppSettingsFormRequest, appsettings.GetAppSettingsFormResponse](p.client.GetForm)(ctx, in)
}
func (p *DevPortalAppSettingsProxy) ValidateForm(ctx context.Context, in *appsettings.ValidateAppSettingsFormRequest) (*appsettings.ValidateAppSettingsFormResponse, error) {
	return proxyutil.ProxyMethod[appsettings.ValidateAppSettingsFormRequest, appsettings.ValidateAppSettingsFormResponse](p.client.ValidateForm)(ctx, in)
}
func (p *DevPortalAppSettingsProxy) GetSettings(ctx context.Context, in *appsettings.GetAppSettingsRequest) (*appsettings.GetAppSettingsResponse, error) {
	return proxyutil.ProxyMethod[appsettings.GetAppSettingsRequest, appsettings.GetAppSettingsResponse](p.client.GetSettings)(ctx, in)
}
func (p *DevPortalAppSettingsProxy) UpdateSettings(ctx context.Context, in *appsettings.UpdateAppSettingsRequest) (*appsettings.UpdateAppSettingsResponse, error) {
	return proxyutil.ProxyMethod[appsettings.UpdateAppSettingsRequest, appsettings.UpdateAppSettingsResponse](p.client.UpdateSettings)(ctx, in)
}
